// WF03 Map Upsert Result — Run Once for Each Item
const res = $json;
const status = res.statusCode;
const body = res.body ?? {};
const correlationId = $node['POST Upsert'].json.headers?.['x-correlation-id'];
const success = status === 200 || status === 201;
return { json: { success, statusCode: status, operation: status === 201 ? 'created' : status === 200 ? 'updated' : 'none', lead: success ? body.data : null, error: success ? null : (body.error ?? { code: 'UNKNOWN' }), correlationId } };
